<!DOCTYPE html>
<html lang="ro">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Autentificare - Boxing Champions Admin</title>
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.1/css/all.min.css">
    <style>
        :root {
            --bg-dark: #0a0a0a;
            --bg-panel: #111111;
            --gold: #d4af37;
            --gold-light: #f0c040;
            --gold-dark: #b8941f;
            --red: #c0392b;
            --red-light: #e74c3c;
            --text: #e0e0e0;
            --text-muted: #999;
            --glass-bg: rgba(17, 17, 17, 0.75);
            --glass-border: rgba(212, 175, 55, 0.18);
            --glass-shadow: 0 8px 32px rgba(0, 0, 0, 0.55);
            --transition: 0.28s cubic-bezier(0.4, 0, 0.2, 1);
        }

        * { margin: 0; padding: 0; box-sizing: border-box; }

        body {
            font-family: 'Segoe UI', 'Inter', system-ui, -apple-system, sans-serif;
            background: var(--bg-dark);
            color: var(--text);
            min-height: 100vh;
            display: flex;
            align-items: center;
            justify-content: center;
            position: relative;
            overflow: hidden;
            line-height: 1.55;
        }

        /* Background image with overlay */
        .login-bg {
            position: fixed;
            inset: 0;
            z-index: 0;
        }

        .login-bg img {
            width: 100%;
            height: 100%;
            object-fit: cover;
            opacity: 0.25;
            filter: brightness(0.4);
        }

        .login-bg::after {
            content: '';
            position: absolute;
            inset: 0;
            background: radial-gradient(ellipse at center, rgba(10,10,10,0.5) 0%, rgba(10,10,10,0.9) 70%);
        }

        /* Particles canvas */
        #particle-canvas {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            pointer-events: none;
            z-index: 1;
        }

        /* Login card */
        .login-wrapper {
            position: relative;
            z-index: 5;
            width: 100%;
            max-width: 440px;
            padding: 20px;
        }

        .login-card {
            background: var(--glass-bg);
            backdrop-filter: blur(18px) saturate(120%);
            -webkit-backdrop-filter: blur(18px) saturate(120%);
            border: 1px solid var(--glass-border);
            border-radius: 16px;
            padding: 40px 36px;
            box-shadow: var(--glass-shadow);
        }

        .login-logo {
            text-align: center;
            margin-bottom: 28px;
        }

        .login-logo i {
            font-size: 3rem;
            color: var(--gold);
            filter: drop-shadow(0 0 14px rgba(212, 175, 55, 0.5));
            margin-bottom: 8px;
            display: block;
        }

        .login-logo h1 {
            font-size: 1.3rem;
            font-weight: 700;
            color: var(--gold);
            letter-spacing: 0.04em;
            text-transform: uppercase;
        }

        .login-logo p {
            font-size: 0.85rem;
            color: var(--text-muted);
            margin-top: 4px;
        }

        .form-group {
            margin-bottom: 18px;
        }

        .form-group label {
            display: block;
            font-weight: 600;
            font-size: 0.82rem;
            color: var(--gold-light);
            margin-bottom: 6px;
            text-transform: uppercase;
            letter-spacing: 0.04em;
        }

        .input-wrapper {
            position: relative;
            display: flex;
            align-items: center;
