    <script>
        (function () {
            'use strict';

            // DOM elements
            var loginForm = document.getElementById('loginForm');
            var loginError = document.getElementById('loginError');
            var loginErrorMessage = document.getElementById('loginErrorMessage');
            var btnLogin = document.getElementById('btnLogin');
            var emailInput = document.getElementById('email');
            var passwordInput = document.getElementById('password');
            var particleCanvas = document.getElementById('particle-canvas');

            // -------------------------------------------------------------------
            // Particles background
            // -------------------------------------------------------------------
            function initParticles() {
                var ctx = particleCanvas.getContext('2d');
                var particles = [];
                var COUNT = 50;
                var PALETTE = [
                    'rgba(212,175,55,0.22)',
                    'rgba(240,192,64,0.18)',
                    'rgba(184,148,31,0.24)',
                    'rgba(230,180,50,0.16)',
                    'rgba(200,160,40,0.20)'
                ];

                function resize() {
                    particleCanvas.width = window.innerWidth;
                    particleCanvas.height = window.innerHeight;
                }
                window.addEventListener('resize', resize);
                resize();

                function mk() {
                    return {
                        x: Math.random() * particleCanvas.width,
                        y: Math.random() * particleCanvas.height,
                        radius: Math.random() * 2.8 + 0.8,
                        speedX: (Math.random() - 0.5) * 0.35,
                        speedY: (Math.random() - 0.5) * 0.35,
                        color: PALETTE[Math.floor(Math.random() * PALETTE.length)],
                        opacity: Math.random() * 0.6 + 0.2,
                        pulse: Math.random() * Math.PI * 2,
                        pulseSpeed: Math.random() * 0.015 + 0.005
                    };
                }

                for (var i = 0; i < COUNT; i++) {
                    particles.push(mk());
                }

                function animate() {
                    ctx.clearRect(0, 0, particleCanvas.width, particleCanvas.height);

                    for (var i = 0; i < particles.length; i++) {
                        var p = particles[i];
                        p.x += p.speedX;
                        p.y += p.speedY;
                        p.pulse += p.pulseSpeed;
                        var o = p.opacity + Math.sin(p.pulse) * 0.12;

                        if (p.x < -10) p.x = particleCanvas.width + 10;
                        if (p.x > particleCanvas.width + 10) p.x = -10;
                        if (p.y < -10) p.y = particleCanvas.height + 10;
                        if (p.y > particleCanvas.height + 10) p.y = -10;

                        ctx.beginPath();
                        ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
                        ctx.fillStyle = p.color.replace(/[\d.]+\)$/, Math.max(0.04, Math.min(0.5, o)) + ')');
                        ctx.fill();
                    }

                    for (var i2 = 0; i2 < particles.length; i2++) {
                        for (var j = i2 + 1; j < particles.length; j++) {
                            var dx = particles[i2].x - particles[j].x;
                            var dy = particles[i2].y - particles[j].y;
                            var dist = Math.sqrt(dx * dx + dy * dy);
                            if (dist < 100) {
                                ctx.beginPath();
                                ctx.moveTo(particles[i2].x, particles[i2].y);
                                ctx.lineTo(particles[j].x, particles[j].y);
                                ctx.strokeStyle = 'rgba(212,175,55,' + (0.06 * (1 - dist / 100)) + ')';
                                ctx.lineWidth = 0.5;
                                ctx.stroke();
                            }
                        }
                    }

                    requestAnimationFrame(animate);
                }

                animate();
            }

            // -------------------------------------------------------------------
            // Error display
            // -------------------------------------------------------------------
            function showError(message) {
                loginErrorMessage.textContent = message;
                loginError.classList.add('visible');
            }

            function hideError() {
                loginError.classList.remove('visible');
                loginErrorMessage.textContent = '';
            }

            // -------------------------------------------------------------------
            // Loading state
            // -------------------------------------------------------------------
            function setLoading(isLoading) {
                if (isLoading) {
                    btnLogin.disabled = true;
                    btnLogin.innerHTML = '<span class="spinner"></span> Se autentifică...';
                } else {
                    btnLogin.disabled = false;
                    btnLogin.innerHTML = '<i class="fa-solid fa-right-to-bracket"></i> Autentificare';
                }
            }

            // -------------------------------------------------------------------
            // Form submit handler
            // -------------------------------------------------------------------
            loginForm.addEventListener('submit', function (e) {
                e.preventDefault();
                hideError();

                var email = emailInput.value.trim();
                var password = passwordInput.value;

                // Basic client-side validation
                if (!email || !password) {
                    showError('Completează email-ul și parola.');
                    return;
                }

                if (!/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/i.test(email)) {
                    showError('Adresa de email nu este validă.');
                    return;
                }

                setLoading(true);

                fetch('/api/auth/login', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'Accept': 'application/json'
                    },
                    credentials: 'same-origin',
                    body: JSON.stringify({ email: email, password: password })
                })
                .then(function (response) {
                    return response.json().then(function (data) {
                        return { status: response.status, data: data };
                    });
                })
                .then(function (result) {
                    if (result.data && result.data.success) {
                        // Autentificare reușită
                        window.location.href = result.data.redirect || '/admin/dashboard';
                        return;
                    }

                    // Autentificare eșuată — citește atât `message` cât și `error`
                    var msg = (result.data && (result.data.message || result.data.error))
                        ? (result.data.message || result.data.error)
                        : 'Email sau parolă incorecte.';

                    showError(msg);
                    setLoading(false);
                })
                .catch(function (err) {
                    // Eroare de rețea sau JSON invalid
                    showError('Eroare de conexiune. Verifică internetul și reîncearcă.');
                    setLoading(false);
                });
            });

            // -------------------------------------------------------------------
            // Hide error on input
            // -------------------------------------------------------------------
            emailInput.addEventListener('input', hideError);
            passwordInput.addEventListener('input', hideError);

            // -------------------------------------------------------------------
            // Init
            // -------------------------------------------------------------------
            initParticles();
        })();
    </script>
</body>
</html>
