            const particleCanvas = document.getElementById('particle-canvas');

            function escapeHtml(str) { const d = document.createElement('div'); d.textContent = str; return d.innerHTML; }
            function showToast(msg, type) {
                type = type || 'success';
                const icons = { success: 'fa-circle-check', error: 'fa-circle-xmark', info: 'fa-circle-info' };
                const t = document.createElement('div');
                t.className = 'toast toast--' + type;
                t.innerHTML = '<i class="fa-solid ' + (icons[type]||icons.info) + '"></i> ' + escapeHtml(msg);
                toastContainer.appendChild(t);
                setTimeout(function() {
                    t.style.animation = 'toastSlideOut 0.3s ease forwards';
                    t.addEventListener('animationend', function() { if (t.parentNode) t.parentNode.removeChild(t); });
                }, 3200);
            }
            async function apiRequest(url, opts) {
                opts = opts || {};
                opts.headers = Object.assign({}, opts.headers, { 'Content-Type': 'application/json', 'Accept': 'application/json' });
                opts.credentials = 'include';
                try {
                    const resp = await fetch(url, opts);
                    if (resp.status === 401) { window.location.href = '/admin'; throw new Error('Neautentificat'); }
                    if (!resp.ok) { const ed = await resp.json().catch(function() { return {}; }); throw new Error(ed.message || ed.error || 'Eroare server (' + resp.status + ')'); }
                    return await resp.json();
                } catch (err) {
                    if (err.message === 'Neautentificat') throw err;
                    showToast(err.message || 'Eroare de rețea', 'error');
                    throw err;
                }
            }
            function renderSpinner() { return '<div class="empty-state"><div class="spinner"></div><p style="margin-top:12px;">Se încarcă…</p></div>'; }

            function initParticles() {
                const ctx = particleCanvas.getContext('2d');
                let particles = [];
                const COUNT = 65;
                const PALETTE = ['rgba(212,175,55,0.22)','rgba(240,192,64,0.18)','rgba(184,148,31,0.24)','rgba(230,180,50,0.16)','rgba(200,160,40,0.20)'];
                function resize() { particleCanvas.width = window.innerWidth; particleCanvas.height = window.innerHeight; }
                window.addEventListener('resize', resize); resize();
                function mk() { return { x: Math.random()*particleCanvas.width, y: Math.random()*particleCanvas.height, radius: Math.random()*2.8+0.8, speedX: (Math.random()-0.5)*0.35, speedY: (Math.random()-0.5)*0.35, color: PALETTE[Math.floor(Math.random()*PALETTE.length)], opacity: Math.random()*0.6+0.2, pulse: Math.random()*Math.PI*2, pulseSpeed: Math.random()*0.015+0.005 }; }
                for (let i = 0; i < COUNT; i++) particles.push(mk());
                function animate() {
                    ctx.clearRect(0, 0, particleCanvas.width, particleCanvas.height);
                    for (let i = 0; i < particles.length; i++) {
                        const p = particles[i];
                        p.x += p.speedX; p.y += p.speedY; p.pulse += p.pulseSpeed;
                        const o = p.opacity + Math.sin(p.pulse) * 0.12;
                        if (p.x < -10) p.x = particleCanvas.width + 10;
                        if (p.x > particleCanvas.width + 10) p.x = -10;
                        if (p.y < -10) p.y = particleCanvas.height + 10;
                        if (p.y > particleCanvas.height + 10) p.y = -10;
                        ctx.beginPath(); ctx.arc(p.x, p.y, p.radius, 0, Math.PI*2);
                        ctx.fillStyle = p.color.replace(/[\d.]+\)$/, Math.max(0.04, Math.min(0.5, o)) + ')');
                        ctx.fill();
                    }
                    for (let i = 0; i < particles.length; i++) {
                        for (let j = i + 1; j < particles.length; j++) {
                            const dx = particles[i].x - particles[j].x, dy = particles[i].y - particles[j].y;
                            const dist = Math.sqrt(dx*dx + dy*dy);
                            if (dist < 100) { ctx.beginPath(); ctx.moveTo(particles[i].x, particles[i].y); ctx.lineTo(particles[j].x, particles[j].y); ctx.strokeStyle = 'rgba(212,175,55,' + (0.06*(1 - dist/100)) + ')'; ctx.lineWidth = 0.5; ctx.stroke(); }
                        }
                    }
                    requestAnimationFrame(animate);
                }
                animate();
            }

            async function checkAuth() {
                try {
                    const r = await fetch('/api/auth/check', { method: 'GET', credentials: 'include', headers: { 'Accept': 'application/json' } });
                    const d = await r.json();
                    // Tratează corect răspunsul { authenticated: false } (status 200)
                    if (!d.authenticated) { window.location.href = '/admin'; return false; }
                    return true;
                } catch (e) { window.location.href = '/admin'; return false; }
            }

            async function loadSection(sk) {
                const sec = SECTIONS[sk]; if (!sec) return;
                mainPanel.innerHTML = '<div class="section-header"><h1><i class="fa-solid '+sec.icon+'"></i> '+sec.label+'</h1><button class="btn btn-gold" id="btnAddNew" aria-label="Adaugă nou în '+sec.label+'"><i class="fa-solid fa-plus"></i> Adaugă</button></div><div class="glass-table-wrap">'+renderSpinner()+'</div>';
                document.getElementById('btnAddNew').addEventListener('click', function() { openModal(sk, null); });
                try {
                    const data = await apiRequest(sec.apiBase, { method: 'GET' });
                    const items = Array.isArray(data) ? data : (data.data || data.items || data.results || []);
                    renderTable(sk, items);
                } catch (err) { if (err.message !== 'Neautentificat') { mainPanel.querySelector('.glass-table-wrap').innerHTML = '<div class="empty-state"><i class="fa-solid fa-triangle-exclamation"></i><p>Eroare la încărcarea datelor. Verifică conexiunea.</p></div>'; } }
            }

            function renderTable(sk, items) {
                const sec = SECTIONS[sk], wrap = mainPanel.querySelector('.glass-table-wrap');
                if (!items || items.length === 0) { wrap.innerHTML = '<div class="empty-state" style="padding:40px;"><i class="fa-solid '+sec.icon+'"></i><p>Nu există înregistrări în '+sec.label.toLowerCase()+'.</p><p style="font-size:0.85rem;margin-top:6px;">Apasă butonul <strong>Adaugă</strong> pentru a crea prima înregistrare.</p></div>'; return; }
                let h = '<table role="grid" aria-label="'+escapeHtml(sec.label)+'"><thead><tr>';
                sec.columns.forEach(function(c) { h += '<th scope="col">'+escapeHtml(c)+'</th>'; });
                h += '<th scope="col">Acțiuni</th></tr></thead><tbody>';
                items.forEach(function(it) { h += sec.rowRenderer(it); });
                h += '</tbody></table>'; wrap.innerHTML = h;
                wrap.querySelector('table').addEventListener('click', function(e) {
                    const btn = e.target.closest('button'); if (!btn) return;
                    const action = btn.getAttribute('data-action'), id = btn.getAttribute('data-id');
                    if (action === 'edit') { const it = items.find(function(x) { return String(x.id) === String(id); }); openModal(sk, it || null); }
                    else if (action === 'delete') { confirmDelete(sk, id); }
                });
            }

            function openModal(sk, item) {
                const sec = SECTIONS[sk]; editingId = item ? item.id : null;
                modalTitleText.textContent = item ? 'Editare ' + sec.label : 'Adaugă ' + sec.label;
                let fh = '';
                sec.fields.forEach(function(f) {
                    const v = item ? (item[f.name] || '') : '';
                    fh += '<div class="form-group"><label for="field_'+f.name+'">'+escapeHtml(f.label)+(f.required?' <span style="color:var(--red-light);">*</span>':'')+'</label>';
                    if (f.type === 'textarea') { fh += '<textarea id="field_'+f.name+'" name="'+f.name+'" '+(f.required?'required':'')+'>'+escapeHtml(v)+'</textarea>'; }
                    else if (f.type === 'select' && f.options) { fh += '<select id="field_'+f.name+'" name="'+f.name+'" '+(f.required?'required':'')+'>'; f.options.forEach(function(o) { fh += '<option value="'+escapeHtml(o)+'"'+(String(v)===String(o)?' selected':'')+'>'+escapeHtml(o)+'</option>'; }); fh += '</select>'; }
                    else { const it = f.type || 'text', st = f.step ? ' step="'+f.step+'"' : ''; fh += '<input type="'+it+'" id="field_'+f.name+'" name="'+f.name+'" value="'+escapeHtml(v)+'" '+(f.required?'required':'')+st+'>'; }
                    fh += '</div>';
                });
                fh += '<div class="form-actions"><button type="button" class="btn btn-outline" id="btnCancelModal">Anulează</button><button type="submit" class="btn btn-gold"><i class="fa-solid fa-floppy-disk"></i> Salvează</button></div>';
                modalForm.innerHTML = fh; modalOverlay.classList.add('active'); modalOverlay.setAttribute('aria-hidden', 'false');
                setTimeout(function() { const fi = modalForm.querySelector('input, select, textarea'); if (fi) fi.focus(); }, 150);
                document.getElementById('btnCancelModal').addEventListener('click', closeModal);
                modalForm.onsubmit = async function(e) { e.preventDefault(); await submitForm(sk); };
            }

            function closeModal() { modalOverlay.classList.remove('active'); modalOverlay.setAttribute('aria-hidden', 'true'); modalForm.innerHTML = ''; editingId = null; }

            async function submitForm(sk) {
                const sec = SECTIONS[sk], fd = new FormData(modalForm), payload = {};
                sec.fields.forEach(function(f) { let v = fd.get(f.name) || ''; if (f.type === 'number') v = v === '' ? null : parseFloat(v); payload[f.name] = v; });
                try {
                    const url = editingId ? sec.apiBase + '/' + editingId : sec.apiBase;
                    await apiRequest(url, { method: editingId ? 'PUT' : 'POST', body: JSON.stringify(payload) });
                    showToast(editingId ? 'Înregistrare actualizată cu succes!' : 'Înregistrare adăugată cu succes!', 'success');
                    closeModal(); loadSection(sk);
                } catch (err) {}
            }

            async function confirmDelete(sk, id) {
                const sec = SECTIONS[sk];
                if (!confirm('Ești sigur că vrei să ștergi această înregistrare din ' + sec.label.toLowerCase() + '? Această acțiune este ireversibilă.')) return;
                try { await apiRequest(sec.apiBase + '/' + id, { method: 'DELETE' }); showToast('Înregistrare ștearsă cu succes!', 'success'); loadSection(sk); } catch (err) {}
            }

            sidebarNav.addEventListener('click', function(e) { const ni = e.target.closest('.nav-item'); if (!ni) return; const sk = ni.getAttribute('data-section'); if (sk) switchSection(sk); });
            sidebarNav.addEventListener('keydown', function(e) { if (e.key === 'Enter' || e.key === ' ') { const ni = e.target.closest('.nav-item'); if (!ni) return; e.preventDefault(); const sk = ni.getAttribute('data-section'); if (sk) switchSection(sk); } });

            function switchSection(sk) {
                currentSection = sk;
                sidebarNav.querySelectorAll('.nav-item').forEach(function(it) { it.classList.remove('active'); it.removeAttribute('aria-current'); });
                const ai = sidebarNav.querySelector('[data-section="'+sk+'"]'); if (ai) { ai.classList.add('active'); ai.setAttribute('aria-current', 'page'); }
                loadSection(sk);
                if (window.innerWidth <= 768) sidebar.classList.remove('open');
            }

            closeModalBtn.addEventListener('click', closeModal);
            modalOverlay.addEventListener('click', function(e) { if (e.target === modalOverlay) closeModal(); });
            document.addEventListener('keydown', function(e) { if (e.key === 'Escape' && modalOverlay.classList.contains('active')) closeModal(); });

            btnLogout.addEventListener('click', async function() {
                if (!confirm('Ești sigur că vrei să te deconectezi?')) return;
                try { await apiRequest('/api/auth/logout', { method: 'POST' }); } catch (err) {}
                window.location.href = '/admin';
            });

            mobileMenuToggle.addEventListener('click', function() { sidebar.classList.toggle('open'); });
            document.addEventListener('click', function(e) { if (window.innerWidth <= 768 && !sidebar.contains(e.target) && e.target !== mobileMenuToggle && !mobileMenuToggle.contains(e.target)) sidebar.classList.remove('open'); });

            async function init() { initParticles(); const auth = await checkAuth(); if (!auth) return; loadSection(currentSection); showToast('Bine ai venit în panoul de administrare!', 'info'); }
            init();
        })();
    </script>
</body>
</html>
